import { Button } from '@material-ui/core'
import React, { useRef, useState } from 'react'
import styled from 'styled-components'
import ShoppingBasketIcon from '@material-ui/icons/ShoppingBasket';
import video from '../../video/desktop.mkv'
import video2 from '../../video/mobile.mkv'
import illustration from '../../images/illustration.svg'
import Bubbles from '../../components/Bubbles';
import AboutSection from './AboutSection';
import ClientReviewsSection from './ClientReviewsSection';
import {motion} from 'framer-motion'
import Loading from '../../components/Loading'
import { useHistory } from 'react-router-dom';
import FormReviewSection from './FormReviewSection';
import ArrowForwardIosIcon from '@material-ui/icons/ArrowForwardIos';

export default function Homepage({cursor, outline, lang}) {
    const history = useHistory()
    const v1Ref = useRef()
    const v2Ref = useRef()
    const [turn, setTurn] = useState(true)

    const container = {
        hidden: { opacity: 0 },
        show: {
          opacity: 1,
          transition: {
            staggerChildren: 0.2,
            staggerDirection: -1,
            delayChildren: 1.3,
          }
        }
    }
    
    const item = {
        hidden: { opacity: 0, x: -100 },
        show: { opacity: 1, x: 0 }
    }

    const handleEnter = () => {
        cursor.current.classList.remove('outLink3')
        cursor.current.classList.add('onLink3')
    }
    const handleLeave = () => {
        cursor.current.classList.add('outLink3')
        cursor.current.classList.remove('onLink3')
        setTimeout(() => {
            cursor.current.classList.remove('outLink3')
        }, 1000);
    }

    const switchVideos = () => {
        if (turn) {
            v1Ref.current.style.transform = "translate(1000px, -50%)"
            v2Ref.current.style.transform = "translate(-50%, -50%)"
        } else {
            v1Ref.current.style.transform = "translate(0px, -50%)"
            v2Ref.current.style.transform = "translate(1000px, -50%)"
        }
        setTurn(!turn)
    }

    return (
        <>
            <Loading />

            <Container >
                <Bubbles outline={outline}/>

                <WelcomeSection>
                    <Left as={motion.article} variants={container} initial="hidden" animate="show" >
                        <H2 as={motion.h2} variants={item}>
                            {lang.includes("ro") ? 
                            "Site-uri, pagini web, bloguri pentru desktop și mobil" : 
                            "Sites, web pages, blogs for desktop and mobile"}
                        </H2>
                        <H1 as={motion.h1} variants={item}> 
                            {lang.includes("ro") ? 
                            <>Website-ul <b>tău</b> ● reclama mea</> : 
                            <><b>Your</b> website ● my commercial</>}
                        </H1>
                        <P as={motion.p} variants={item}>
                        {lang.includes("ro") ? 
                            <>Programator <b>Front-End</b>, mă ocup cu schițarea și construirea de website-uri, site-uri e-commerce pentru vânzări online cu bază de date, autentificare Google și plată online cu cardul pentru clienți mici și foarte mici. Încă la început de drum în acest domeniu pun suflet și pasiune în fiecare proiect.</> : 
                            <><b>Font-End</b> Developer, I sketch, design and build websites, e-commerce web shops for different sales, with database, authentication and online payment for small clients. Still at the start of my career, I put soul and passion in every project.</>}
                        </P>
                        <Button 
                            component={motion.button} 
                            variants={item} 
                            size="small" 
                            endIcon={<ShoppingBasketIcon/>}
                            onClick={() => history.push("/cumpara")}
                            onMouseEnter={handleEnter} 
                            onMouseLeave={handleLeave}
                        >
                            {lang.includes("ro") ? "cumpără" : "buy now"}
                        </Button>
                    </Left> 

                    <Right>
                        <VideoContainer ref={v1Ref}>
                            <Video 
                                src={video} type="video/mkv" 
                                controls 
                                muted 
                                loop
                            >
                            </Video>
                        </VideoContainer>
                        <VideoContainer2 ref={v2Ref}>
                            <Video
                                src={video2} type="video/mkv" 
                                controls 
                                muted 
                                loop    
                            >
                            </Video>
                        </VideoContainer2>
                       
                        <Illustration 
                            as={motion.img} 
                            initial={{opacity: 0}} 
                            animate={{opacity: 1}} 
                            transition={{delay: 1.3, duration: 1}} 
                            src={illustration} 
                            alt="illustration" 
                        />

                        <ArrowForwardIosIcon onClick={switchVideos}/>
                    </Right>
                </WelcomeSection>  

                <AboutSection cursor={cursor} lang={lang}/>

                <ClientReviewsSection lang={lang}/>

                <FormReviewSection cursor={cursor} lang={lang}/>
            </Container>
        </>
    )
}


const Container = styled.main`
    position: relative;
    overflow: hidden;
    `
const WelcomeSection = styled.div`
    padding: 0 5vw;
    min-height: calc(100vh - 100px);
    position: relative;
    z-index: 1;
    display: flex;
    margin: 0 auto;
    max-width: 1500px;
    gap: 10vw; 
    pointer-events: none;
    @media screen and (max-width: 1000px) {
        flex-direction: column;
    }
`
const Left = styled.article`
    flex: 1;
    margin: 50px 0 0;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: flex-start;
    >button {
        border-radius: 10px;
        background: linear-gradient(125deg, var(--crd), var(--crl));
        color: white;
        font-family: var(--fsss);
        margin-top: 20px;
        padding: 10px 20px;
        pointer-events: all;
        &:hover {
            background: linear-gradient(125deg, var(--crd), var(--crd));
            animation: bounce 2s both;
            @keyframes bounce { 
                0%, 30%, 50%, 80%, 100% {
                transform: translateY(0);
                } 
                20% {
                    transform: translateY(-7px);
                }
                40% {
                    transform: translateY(-5px);
                } 
                60% {
                    transform: translateY(-2px);
                } 
            }
        }
    }
    @media screen and (max-width: 1000px) {
        text-align: center;
        align-items: center;
    }
`
const H2 = styled.h2`
    font-size: var(--mf);
    font-family: var(--fsss);
    font-weight: 200;
    color: grey;
    line-height: 1;
`
const H1 = styled.h1`
    font-size: var(--bf);
    font-family: var(--fsss);
    color: #2e2e2e;
    font-weight: 500;
    line-height: 1;
    margin-top: var(--sf);
    margin-bottom: var(--bf);
    >b {
        color: var(--cbd);
    }
`
const P = styled.p`
    font-size: var(--sf);
    line-height: 1.6;
    >b {
        color: var(--cbl);
    }
`
const Right = styled.article`
    min-height: 50vh;
    width: 100%;
    flex: 1;
    display: grid;
    place-content: center;
    place-items: center;
    position: relative;
    >svg {
        position: absolute;
        right: -20px;
        top: 50%;
        transform: translateY(-50%);
        font-size: 1.5rem;
        color: #5a5a5a9d;
        cursor: pointer;
        z-index: 10;
        pointer-events: all;
        &:hover {
            color: black;
        }
    }
`
const VideoContainer = styled.section`
    box-shadow: 0 19px 38px rgba(0,0,0,0.30), 0 15px 32px rgba(0,0,0,0.22);
    position: absolute;
    top: 50%;
    left: 0;
    transform: translate(0, -50%);
    transition: all 1s ease;
`
const VideoContainer2 = styled.section`
    box-shadow: 0 19px 38px rgba(0,0,0,0.30), 0 15px 32px rgba(0,0,0,0.22);
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(1000px, -50%);
    transition: all 1s ease;
`
const Video = styled.video`
    width: 100%;
    max-height: 500px;
    pointer-events: all;
    display: block;
    @media screen and (max-width: 1000px) {
        max-height: 50vh;
    }
`
const Illustration = styled.img`
    position: absolute;
    bottom: 50%;
    left: 50%;
    object-fit: contain;
    transform: translate(-50%, 50%);
    width: 120%;
    pointer-events: none;
    @media screen and (max-width: 1000px) {
        display: none;
    }
`