import { Checkbox, FormControl } from '@material-ui/core'
import { Select } from '@material-ui/core'
import { TextField } from '@material-ui/core'
import { MenuItem } from '@material-ui/core'
import { InputLabel } from '@material-ui/core'
import { Grid } from '@material-ui/core'
import styled from 'styled-components'
import { motion, useAnimation  } from 'framer-motion'
import { useInView } from 'react-intersection-observer';
import { useEffect } from 'react'
import {Link} from 'react-router-dom'

export default function FormSection({ domain, setDomain, option, setOption, email, setEmail, message, setMessage, name, setName, phone, setPhone, userEmail, setUserEmail, terms, setTerms, payment, setPayment, lang}) {
    
    const controls = useAnimation();
    const { ref, inView } = useInView({
        "triggerOnce": true
    });

    useEffect(() => {
        if (inView) {
            controls.start('visible');
        }
        if (!inView) {
            controls.start('hidden');
        }
    }, [controls, inView]);

    const wrapperVariants = {
        hidden: {scale: 0},
        visible: i => ({
            scale: 1,
            transition: {
                duration: 0.5,
                delay: i * 0.1
            }
        })
    }
    
    return (
        <Container ref={ref}>
            <Grid container spacing={1}>
                <Grid
                component={motion.div}
                custom={0}
                variants={wrapperVariants}
                initial="hidden"
                animate={controls}
                item xs={12} sm={12}>
                    <TextField
                        required
                        id="name"
                        name="name"
                        fullWidth
                        label={lang.includes("ro") ? "Nume" : "Name"}
                        variant="filled"
                        type="text"
                        value={name}
                        onChange={e => setName(e.target.value)}  
                    />
                </Grid>
                <Grid 
                component={motion.div}
                custom={1}
                variants={wrapperVariants}
                initial="hidden"
                animate={controls}
                item xs={12} sm={12}>
                    <TextField
                        required
                        id="userEmail"
                        name="user email"
                        fullWidth
                        label="Email"
                        variant="filled"
                        type="email"
                        value={userEmail}
                        onChange={e => setUserEmail(e.target.value)}  
                    />
                </Grid>
                <Grid 
                component={motion.div}
                custom={2}
                variants={wrapperVariants}
                initial="hidden"
                animate={controls}
                item xs={12} sm={12}>
                    <TextField
                        required
                        id="phoneNumber"
                        name="phone number"
                        fullWidth
                        label={lang.includes("ro") ? "Număr telefon" : "Phone number"}
                        variant="filled"
                        type="number"
                        value={phone}
                        onChange={e => setPhone(e.target.value)}  
                    />
                </Grid>
                <Grid 
                component={motion.div}
                custom={3}
                variants={wrapperVariants}
                initial="hidden"
                animate={controls}
                item xs={12} sm={8}>
                    <TextField  
                        id="domain-name" 
                        name="domain"
                        label={lang.includes("ro") ? "Nume domeniu" : "Domain name"}
                        type="text" 
                        fullWidth 
                        variant="filled"
                        value={domain}
                        onChange={e => setDomain(e.target.value)}
                    />
                </Grid>
                <Grid 
                component={motion.div}
                custom={3}
                variants={wrapperVariants}
                initial="hidden"
                animate={controls}
                item xs={12} sm={4}>
                    <FormControl fullWidth>
                        <InputLabel id="demo-simple-select-helper-label">{lang.includes("ro") ? "Alege domeniu" : "Choose domain"}</InputLabel>
                        <Select
                            name="options"
                            variant="filled"
                            labelId="demo-simple-select-helper-label"
                            id="demo-simple-select-helper"
                            required
                            value={option}
                            onChange={e => setOption(e.target.value)}
                        >
                            <MenuItem value="">
                                <em>None</em>
                            </MenuItem>
                            <MenuItem value={0}>▸ github.io/ - {lang.includes("ro") ? <>0 RON/an</> : <>&euro; 0/year</>}</MenuItem>
                            <MenuItem value={40}>▸ {lang.includes("ro") ? <>.ro/altele - 40 RON/an</> : <>.ro/others - &euro; 7.49/year</>}</MenuItem>
                            <MenuItem value={50}>▸ .com - {lang.includes("ro") ? <>50 RON/an</> : <>&euro; 9.90/year</>}</MenuItem>
                            <MenuItem value={75}>▸ .info - {lang.includes("ro") ? <>75 RON/an</> : <>&euro; 14.99/year</>}</MenuItem>
                        </Select>
                    </FormControl>
                </Grid>
                <Grid 
                component={motion.div}
                custom={4}
                variants={wrapperVariants}
                initial="hidden"
                animate={controls}
                item xs={12} sm={12}>
                    <TextField  
                        name="email"
                        label={lang.includes("ro") ? "Business Email - 26 RON/lună x 12" : <>Business Email - &euro; 5.20/month x 12</>}
                        placeholder={lang.includes("ro") ? "emailultău@domeniultău.ro" : "youremail@yourdomain.com"}
                        type="email" 
                        value={email}
                        onChange={e => setEmail(e.target.value)}
                        fullWidth 
                        variant="filled"/>
                </Grid>
                <Grid 
                component={motion.div}
                custom={6}
                variants={wrapperVariants}
                initial="hidden"
                animate={controls}
                item xs={12} sm={12}>
                    <TextField
                        fullWidth
                        name="description"
                        id="standard-multiline-static"
                        label={lang.includes("ro") ? "Descriere website/adaugă linkuri" : "Website description/show relative links"}
                        multiline
                        rows={6}
                        spellCheck={false}
                        variant="filled"
                        required
                        value={message}
                        onChange={(e) => setMessage(e.target.value)}
                    />
                </Grid>
                <Grid 
                    component={motion.div}
                    custom={7}
                    variants={wrapperVariants}
                    initial="hidden"
                    animate={controls}
                    item xs={12} sm={12}>
                    <InputLabel htmlFor="payment" style={{cursor: 'pointer'}}>
                        <Checkbox 
                            id="payment"
                            checked={payment} 
                            color="primary" 
                            onChange={() => setPayment(!payment)} 
                            name="card payment" 
                        />
                        {lang.includes("ro") ? <small>Integrare plata online cu cardul (500 RON)</small> :
                                        <small>Integration of online payments (&euro; 100)</small>}
                    </InputLabel>
                </Grid>
                <Grid 
                    component={motion.div}
                    custom={8}
                    variants={wrapperVariants}
                    initial="hidden"
                    animate={controls}
                    item xs={12} sm={12}>
                    <InputLabel htmlFor="checkbox" style={{cursor: 'pointer'}}>
                        <Checkbox 
                            required
                            id="checkbox"
                            checked={terms} 
                            color="primary" 
                            onChange={() => setTerms(!terms)} 
                            name="terms and conditions" 
                        />
                        <small>Accept <Link to="termeni-si-conditii" target="_blank" onClick={() => window.scrollTo(0, 0)} >{lang.includes("ro") ? "Termenii și Condițiile" : "Terms and Conditions"}</Link>
                       </small>
                    </InputLabel>
                </Grid>
            </Grid>
        </Container>
    )
}


const Container = styled.section`
    width: 700px;
    max-width: 96vw;
    margin: 100px auto 20px;
`