import React from 'react'
import { useMemo } from 'react'
import { createRef } from 'react'
import styled from 'styled-components'
import Bubble from './Bubble'
import Bubble2 from './Bubble2'


export default function Bubbles({outline}) {
    const bubbleRef = useMemo(() => Array(30).fill(0).map(i => createRef()), [])
    const bubbleRef2 = useMemo(() => Array(30).fill(0).map(i => createRef()), [])

    return (
        <Container id="container">
            {new Array(30).fill(0).map((bubble, i) => (
                <Bubble  key={i} refr={bubbleRef[i]} outline={outline}/>
            ))}
            {new Array(30).fill(0).map((bubble, i) => (
                <Bubble2  key={i} refr={bubbleRef2[i]} outline={outline}/>
            ))}
        </Container>
    )
}


const Container = styled.section`
    height: 100%;
    position: absolute;
    inset: 0;
`
